script.code:
const allData = {{workflowparams:allData}};
const unique = `${allData.gd_created_by || ""}_${Date.now()}`;

return {
  unique
};

const allData = {{workflowparams:allData}}

const zeroQtyArray = [];
for (const [index, gd] of allData.table_gd.entries()) {
  if (gd.gd_qty <= 0) {
    zeroQtyArray.push(`#${index + 1}`);
  }
}
let hasZero = 0
let message = null;
if (zeroQtyArray.length > 0) {
  message = `Line${zeroQtyArray.length > 1 ? "s" : ""} ${zeroQtyArray.join(
    ", ",
  )} ha${
    zeroQtyArray.length > 1 ? "ve" : "s"
  } a zero deliver quantity, which may prevent processing.\nIf you proceed, it will delete the row with 0 deliver quantity. \nWould you like to proceed?`;
  hasZero = 1
}

let pickingStatus = {{workflowparams:allData.picking_status}} || 'Not Required'

return {
  message,
  hasZero,
  pickingStatus
};

const allData = {{workflowparams:allData}};
const tableGd = allData.table_gd || [];

// Filter rows that need allocation: gd_qty > 0 AND no temp_qty_data
const rowsNeedingAllocation = [];

tableGd.forEach((row, index) => {
  const gdQty = parseFloat(row.gd_qty) || 0;
  const hasTempData = row.temp_qty_data && 
                      row.temp_qty_data !== "[]" && 
                      row.temp_qty_data.trim() !== "";

  // Only allocate if: has quantity AND no existing allocation AND has material_id
  if (gdQty > 0 && !hasTempData && row.material_id) {
    rowsNeedingAllocation.push({
      rowIndex: index,
      materialId: row.material_id,
      quantity: gdQty,
      uomId: row.gd_order_uom_id,
      plantId: allData.plant_id,
      organizationId: allData.organization_id,
      soLineItemId: row.so_line_item_id || null
    });
  }
});

// Initialize allocation tracker for cross-row deduplication
const allocationTracker = {};

return {
  rowsNeedingAllocation,
  allocationTracker,
  plantId: allData.plant_id,
  organizationId: allData.organization_id,
  totalRowsToAllocate: rowsNeedingAllocation.length
};

const allData = {{workflowparams:allData}};
const rowsNeedingAllocation = {{node:code_node_kJx9p9Nh.data.rowsNeedingAllocation}};

// Collect unique UOM IDs
const uomIds = new Set();
rowsNeedingAllocation.forEach(row => {
  if (row.uomId) uomIds.add(row.uomId);
});

return {
  uomIds: Array.from(uomIds)
};

const rowsNeedingAllocation = {{node:code_node_kJx9p9Nh.data.rowsNeedingAllocation}};
const currentIndexRaw = {{node:get_cache_node_ih80ef3f.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;

const currentRow = rowsNeedingAllocation[index];

return {
  currentRow,
  currentIndex: index,
  nextIndex: index + 1
};

// Global Allocation Params (code_node_Htpcyp8t)
// This is the code for the backend workflow node that prepares params for GLOBAL_AUTO_ALLOCATION.
// Copy this into the platform's code node editor.
// CHANGES: Added splitPolicy, lineMaterials to the return object.
//          For FULL_HU_PICK/NO_SPLIT, includes ALL items per HU (not just current material).

const currentRow = {{node:code_node_aay7z3VT.data.currentRow}};
const pickingSetup = {{node:get_node_iFPuvJX2.data.data}};
const rawTracker = {{node:get_cache_node_QGhmYUxQ.data}};
const allData = {{workflowparams:allData}};
const allHUData = {{node:search_node_l8oiJ60B.data.data}} || [];
const isGDPP = allData.is_select_picking || 0;
const gd_status = {{workflowparams:allData.gd_status}} || "Draft";
const rowsNeedingAllocation = {{node:code_node_kJx9p9Nh.data.rowsNeedingAllocation}};

// Split policy from picking setup
const splitPolicy = pickingSetup.split_policy || "ALLOW_SPLIT";
const allowMixedItem = pickingSetup.allow_mixed_item ?? 1;

let allocationTracker = {};
if (rawTracker) {
  if (typeof rawTracker === "string") {
    try {
      allocationTracker = JSON.parse(rawTracker);
    } catch (e) {
      allocationTracker = {};
    }
  } else if (typeof rawTracker === "object") {
    allocationTracker = rawTracker;
  }
}

// Build existingAllocationData from tracker (cross-row deduction)
const existingAllocations = [];
const materialAllocations = allocationTracker[currentRow.materialId] || {};

Object.entries(materialAllocations).forEach(([rIdx, rowAllocs]) => {
  if (parseInt(rIdx) !== currentRow.rowIndex) {
    Object.entries(rowAllocs).forEach(([locationKey, qty]) => {
      const parts = locationKey.split("-");
      const locationId = parts[0];
      let batchId = null;
      let handlingUnitId = null;

      if (parts.length > 1) {
        if (parts[1] === "hu") {
          handlingUnitId = parts[2] || null;
        } else {
          batchId = parts[1] !== "no_batch" ? parts[1] : null;
        }
      }

      existingAllocations.push({
        location_id: locationId,
        batch_id: batchId,
        handling_unit_id: handlingUnitId,
        quantity: qty,
      });
    });
  }
});

// Build HU data from pre-fetched allHUData
const huData = [];
for (const hu of allHUData) {
  // For ALLOW_SPLIT: only include items matching current material
  // For FULL_HU_PICK/NO_SPLIT: include ALL items in HUs that contain current material
  const allActiveItems = (hu.table_hu_items || []).filter(
    (item) => item.is_deleted !== 1,
  );
  const hasCurrentMaterial = allActiveItems.some(
    (item) => item.material_id === currentRow.materialId,
  );
  if (!hasCurrentMaterial) continue;

  const itemsToInclude = splitPolicy === "ALLOW_SPLIT"
    ? allActiveItems.filter((item) => item.material_id === currentRow.materialId)
    : allActiveItems;

  // Header row
  huData.push({
    row_type: "header",
    handling_unit_id: hu.id,
    handling_no: hu.handling_no,
    material_id: "",
    material_name: "",
    storage_location_id: hu.storage_location_id,
    location_id: hu.location_id,
    batch_id: null,
    item_quantity: parseFloat(hu.total_quantity) || 0,
    deliver_quantity: 0,
    remark: hu.remark || "",
    balance_id: "",
  });

  // Item rows
  for (const huItem of itemsToInclude) {
    huData.push({
      row_type: "item",
      handling_unit_id: hu.id,
      handling_no: "",
      material_id: huItem.material_id,
      material_name: huItem.material_name,
      storage_location_id: hu.storage_location_id,
      location_id: huItem.location_id || hu.location_id,
      batch_id: huItem.batch_id || null,
      item_quantity: parseFloat(huItem.quantity) || 0,
      deliver_quantity: 0,
      remark: "",
      balance_id: huItem.balance_id || "",
      expired_date: huItem.expired_date || null,
      manufacturing_date: huItem.manufacturing_date || null,
      create_time: huItem.create_time || hu.create_time,
    });
  }
}

return {
  material_id: currentRow.materialId,
  quantity: currentRow.quantity,
  plant_id: currentRow.plantId,
  organization_id: currentRow.organizationId,
  allocationType: "GD",
  allocationStrategy: pickingSetup.default_strategy_id || "RANDOM",
  isPending: currentRow.soLineItemId ? 1 : 0,
  parent_line_id: currentRow.soLineItemId || "",
  existingAllocationData: existingAllocations,
  huData: huData,
  huPriority: pickingSetup.hu_priority || "HU First",
  currentDocId: allData.id || "",
  enforceStockCheck: 1,
  includeReservedQty: (gd_status === "Created" || isGDPP === 1) ? 1 : 0,
  orderUomId: currentRow.uomId || "",
  splitPolicy: splitPolicy,
  allowMixedItem: allowMixedItem,
  lineMaterials: rowsNeedingAllocation.map((r) => r.materialId),
};

// processAllocationResult - Maps global workflow result to GD row data
// Replaces the result-building part of executeAllocation
// ============================================================================

const currentRow = {{node:code_node_aay7z3VT.data.currentRow}};
const workflowResult = {{node:workflow_node_NwRLmxNW.data}};
const allUOMs = {{node:search_node_pltmkkw3.data.data}} || [];
const allBinLocations = {{node:search_node_nbpWEAFx.data.data}} || [];
const rawTracker = {{node:get_cache_node_QGhmYUxQ.data}};
const huData = {{node:code_node_Htpcyp8t.data.huData}} || [];
const splitPolicy = {{node:code_node_Htpcyp8t.data.splitPolicy}} || "ALLOW_SPLIT";

let allocationTracker = {};
if (rawTracker) {
  if (typeof rawTracker === "string") {
    try {
      allocationTracker = JSON.parse(rawTracker);
    } catch (e) {
      allocationTracker = {};
    }
  } else if (typeof rawTracker === "object") {
    allocationTracker = rawTracker;
  }
}

// Extract allocation result from workflow response
const allocationResult = workflowResult?.data || workflowResult || {};
const allocationData = allocationResult.allocationData || [];

// For whole-HU policies, allocations may include items for other materials
const currentMaterialAllocs = allocationData.filter(
  (a) => !a.material_id || a.material_id === currentRow.materialId,
);
const otherMaterialAllocs = splitPolicy !== "ALLOW_SPLIT"
  ? allocationData.filter(
      (a) => a.material_id && a.material_id !== currentRow.materialId,
    )
  : [];

// Helper: lookup bin location name
const getBinLocationName = (locationId) => {
  const bin = allBinLocations.find((b) => b.id === locationId);
  return bin ? bin.bin_location_combine : locationId;
};

// Helper: lookup UOM name
const getUOMName = (uomId) => {
  const uom = allUOMs.find((u) => u.id === uomId);
  return uom ? uom.uom_name : "";
};

// Helper: lookup handling_no from huData header rows
const getHandlingNo = (handlingUnitId) => {
  const header = huData.find(
    (row) => row.row_type === "header" && row.handling_unit_id === handlingUnitId,
  );
  return header ? header.handling_no : handlingUnitId;
};

// Separate HU and loose allocations (current material only)
const looseAllocations = currentMaterialAllocs.filter((a) => a.source !== "hu");
const huAllocations = currentMaterialAllocs.filter((a) => a.source === "hu");

// Build temp_qty_data (loose + HU combined, same shape as before)
const tempQtyData = currentMaterialAllocs.map((alloc) => {
  const record = {
    material_id: currentRow.materialId,
    location_id: alloc.location_id,
    batch_id: alloc.batch_id || null,
    unrestricted_qty:
      alloc.original_unrestricted_qty || alloc.unrestricted_qty,
    plant_id: currentRow.plantId,
    organization_id: currentRow.organizationId,
    is_deleted: 0,
    gd_quantity: alloc.gd_quantity || 0,
    balance_id: alloc.balance_id || "",
  };

  // Tag HU records so they can be distinguished later
  if (alloc.source === "hu" && alloc.handling_unit_id) {
    record.handling_unit_id = alloc.handling_unit_id;
  }

  return record;
});

// Build temp_hu_data (HU-only allocations for HU-specific processing)
const tempHuData = huAllocations.map((alloc) => ({
  row_type: "item",
  handling_unit_id: alloc.handling_unit_id,
  material_id: alloc.material_id || currentRow.materialId,
  location_id: alloc.location_id,
  batch_id: alloc.batch_id || null,
  balance_id: alloc.balance_id || "",
  deliver_quantity: alloc.gd_quantity || 0,
  item_quantity: alloc.original_unrestricted_qty || alloc.unrestricted_qty || 0,
}));

// Build view_stock summary
const uomName = getUOMName(currentRow.uomId);
const totalAllocated = currentMaterialAllocs.reduce(
  (sum, a) => sum + (a.gd_quantity || 0),
  0,
);

let viewStock = "";

if (totalAllocated > 0) {
  const looseTotal = looseAllocations.reduce(
    (sum, a) => sum + (a.gd_quantity || 0),
    0,
  );
  const huTotal = huAllocations.reduce(
    (sum, a) => sum + (a.gd_quantity || 0),
    0,
  );

  viewStock = `Total: ${totalAllocated} ${uomName}\n\n`;

  if (huAllocations.length > 0 && looseAllocations.length > 0) {
    // Both loose and HU
    viewStock += `LOOSE STOCK:\n`;
    looseAllocations.forEach((alloc, idx) => {
      const binName = getBinLocationName(alloc.location_id);
      let line = `${idx + 1}. ${binName}: ${alloc.gd_quantity} ${uomName}`;
      if (alloc.batch_id) {
        line += `\n[Batch: ${alloc.batch_id}]`;
      }
      viewStock += line + "\n";
    });

    viewStock += `\nHANDLING UNIT:\n`;
    huAllocations.forEach((alloc, idx) => {
      const binName = getBinLocationName(alloc.location_id);
      let line = `${idx + 1}. ${binName}: ${alloc.gd_quantity} ${uomName}`;
      if (alloc.handling_unit_id) {
        line += ` [HU: ${getHandlingNo(alloc.handling_unit_id)}]`;
      }
      if (alloc.batch_id) {
        line += `\n[Batch: ${alloc.batch_id}]`;
      }
      viewStock += line + "\n";
    });
  } else if (huAllocations.length > 0) {
    // HU only
    viewStock += `HANDLING UNIT:\n`;
    huAllocations.forEach((alloc, idx) => {
      const binName = getBinLocationName(alloc.location_id);
      let line = `${idx + 1}. ${binName}: ${alloc.gd_quantity} ${uomName}`;
      if (alloc.handling_unit_id) {
        line += ` [HU: ${getHandlingNo(alloc.handling_unit_id)}]`;
      }
      if (alloc.batch_id) {
        line += `\n[Batch: ${alloc.batch_id}]`;
      }
      viewStock += line + "\n";
    });
  } else {
    // Loose only
    viewStock += `DETAILS:\n`;
    looseAllocations.forEach((alloc, idx) => {
      const binName = getBinLocationName(alloc.location_id);
      let line = `${idx + 1}. ${binName}: ${alloc.gd_quantity} ${uomName}`;
      if (alloc.batch_id) {
        line += `\n[Batch: ${alloc.batch_id}]`;
      }
      viewStock += line + "\n";
    });
  }
}

// Cross-line distribution for whole-HU policies
const crossLineUpdates = {};
const tempExcessData = [];

if (splitPolicy !== "ALLOW_SPLIT" && otherMaterialAllocs.length > 0) {
  const rawTableGD = {{node:get_cache_node_6hmHAVwX.data}};
  let tableGD = [];
  if (rawTableGD) {
    tableGD = typeof rawTableGD === "string" ? JSON.parse(rawTableGD) : rawTableGD;
  }

  // Build material -> line indices map
  const materialLineMap = {};
  tableGD.forEach((line, idx) => {
    if (idx === currentRow.rowIndex) return;
    if (line.material_id) {
      if (!materialLineMap[line.material_id]) materialLineMap[line.material_id] = [];
      materialLineMap[line.material_id].push(idx);
    }
  });

  for (const alloc of otherMaterialAllocs) {
    const targetLines = materialLineMap[alloc.material_id];

    if (!targetLines || targetLines.length === 0) {
      // Foreign item — no matching GD line
      tempExcessData.push({
        handling_unit_id: alloc.handling_unit_id || "",
        handling_no: getHandlingNo(alloc.handling_unit_id),
        material_id: alloc.material_id,
        material_name: alloc.material_name || "",
        quantity: alloc.gd_quantity || 0,
        batch_id: alloc.batch_id || null,
        location_id: alloc.location_id,
        reason: "no_gd_line",
      });
      continue;
    }

    // Distribute to first matching line
    const targetIdx = targetLines[0];
    if (!crossLineUpdates[targetIdx]) {
      crossLineUpdates[targetIdx] = { tempQtyData: [], tempHuData: [] };
    }

    crossLineUpdates[targetIdx].tempQtyData.push({
      material_id: alloc.material_id,
      location_id: alloc.location_id,
      batch_id: alloc.batch_id || null,
      unrestricted_qty: alloc.original_unrestricted_qty || alloc.unrestricted_qty,
      plant_id: currentRow.plantId,
      organization_id: currentRow.organizationId,
      is_deleted: 0,
      gd_quantity: alloc.gd_quantity || 0,
      balance_id: alloc.balance_id || "",
      handling_unit_id: alloc.handling_unit_id || "",
    });

    if (alloc.source === "hu") {
      crossLineUpdates[targetIdx].tempHuData.push({
        row_type: "item",
        handling_unit_id: alloc.handling_unit_id,
        material_id: alloc.material_id,
        location_id: alloc.location_id,
        batch_id: alloc.batch_id || null,
        balance_id: alloc.balance_id || "",
        deliver_quantity: alloc.gd_quantity || 0,
        item_quantity: alloc.original_unrestricted_qty || alloc.unrestricted_qty || 0,
      });
    }
  }
}

// Check for over-pick excess on current material
const currentMaterialTotal = currentMaterialAllocs.reduce(
  (sum, a) => sum + (a.gd_quantity || 0), 0,
);
if (currentMaterialTotal > currentRow.quantity && currentRow.quantity > 0) {
  tempExcessData.push({
    handling_unit_id: currentMaterialAllocs.find((a) => a.handling_unit_id)?.handling_unit_id || "",
    handling_no: "",
    material_id: currentRow.materialId,
    material_name: "",
    quantity: currentMaterialTotal - currentRow.quantity,
    batch_id: null,
    location_id: "",
    reason: "over_pick",
  });
}

// Update allocation tracker for cross-row deduction
const updatedTracker = { ...allocationTracker };
if (!updatedTracker[currentRow.materialId]) {
  updatedTracker[currentRow.materialId] = {};
}

const rowAllocations = {};
currentMaterialAllocs.forEach((alloc) => {
  // Only track loose allocations for cross-row deduction
  // HU stock is independent and already deducted from balances
  if (alloc.source === "hu") return;

  const key = alloc.batch_id
    ? `${alloc.location_id}-${alloc.batch_id}`
    : `${alloc.location_id}`;
  rowAllocations[key] = (rowAllocations[key] || 0) + (alloc.gd_quantity || 0);
});
updatedTracker[currentRow.materialId][currentRow.rowIndex] = rowAllocations;

return {
  temp_qty_data: JSON.stringify(tempQtyData),
  temp_hu_data: JSON.stringify(tempHuData),
  temp_excess_data: JSON.stringify(tempExcessData || []),
  view_stock: viewStock,
  total_allocated: totalAllocated,
  rowIndex: currentRow.rowIndex,
  updatedTracker: updatedTracker,
  crossLineUpdates: crossLineUpdates,
};

// updateRowInTableGd (code_node_56IOJIBu)
// Updated to handle crossLineUpdates and temp_excess_data from split policy.
// Copy this into the platform's code node editor.

const rawtableGD = {{node:get_cache_node_6hmHAVwX.data}};
let tableGD = [];

if (rawtableGD) {
  if (typeof rawtableGD === "string") {
    tableGD = JSON.parse(rawtableGD);
  } else {
    tableGD = rawtableGD;
  }
}

const allocationResult = {{node:code_node_hifFKzmo.data}};
const rowIndex = allocationResult.rowIndex;

// Update current row
if (tableGD[rowIndex]) {
  tableGD[rowIndex].temp_qty_data = allocationResult.temp_qty_data;
  tableGD[rowIndex].temp_hu_data = allocationResult.temp_hu_data;
  tableGD[rowIndex].view_stock = allocationResult.view_stock;

  // Save temp_excess_data on current row
  if (allocationResult.temp_excess_data) {
    tableGD[rowIndex].temp_excess_data = allocationResult.temp_excess_data;
  }

  const gdQty = parseFloat(tableGD[rowIndex].gd_qty) || 0;
  const initialDeliveredQty =
    parseFloat(tableGD[rowIndex].gd_initial_delivered_qty) || 0;
  const orderedQty = parseFloat(tableGD[rowIndex].gd_order_quantity) || 0;

  tableGD[rowIndex].gd_delivered_qty = initialDeliveredQty + gdQty;
  tableGD[rowIndex].gd_undelivered_qty =
    orderedQty - (initialDeliveredQty + gdQty);
}

// Apply cross-line distribution updates from whole-HU policies
const crossLineUpdates = allocationResult.crossLineUpdates || {};
for (const [idx, updates] of Object.entries(crossLineUpdates)) {
  const lineIdx = parseInt(idx);
  if (!tableGD[lineIdx]) continue;

  // Merge with existing temp data on the target line
  let existingQty = [];
  let existingHu = [];
  try {
    if (tableGD[lineIdx].temp_qty_data && tableGD[lineIdx].temp_qty_data !== "[]") {
      existingQty = JSON.parse(tableGD[lineIdx].temp_qty_data);
    }
  } catch (e) { /* ignore */ }
  try {
    if (tableGD[lineIdx].temp_hu_data && tableGD[lineIdx].temp_hu_data !== "[]") {
      existingHu = JSON.parse(tableGD[lineIdx].temp_hu_data);
    }
  } catch (e) { /* ignore */ }

  tableGD[lineIdx].temp_qty_data = JSON.stringify([...existingQty, ...updates.tempQtyData]);
  tableGD[lineIdx].temp_hu_data = JSON.stringify([...existingHu, ...updates.tempHuData]);
}

return {
  tableGD: tableGD,
  updatedTracker: allocationResult.updatedTracker,
};

const allData = {{workflowparams:allData}};
const totalRowsToAllocate = {{node:code_node_kJx9p9Nh.data.totalRowsToAllocate}};

// If no rows were allocated, just return original table_gd
if (totalRowsToAllocate === 0) {
  return { tableGD: allData.table_gd };
}

// Otherwise, get the allocated table from Redis
const rawTableGd = {{node:get_cache_node_wiBIs4cB.data}};

let tableGD = [];
if (typeof rawTableGd === 'string') {
  tableGD = JSON.parse(rawTableGd);
} else {
  tableGD = rawTableGd || allData.table_gd;
}

return { tableGD };

let allData = {{workflowparams:allData}};
const updatedGD = [];
const saveAs = {{workflowparams:saveAs}};
const isForceComplete = {{workflowparams:isForceComplete}};
const pickingSetup = {{node:get_node_iFPuvJX2.data.data}};
const pageStatus = {{workflowparams:pageStatus}}

const skippedRows = [];

if (pickingSetup?.picking_mode === "Auto" && saveAs !== "Cancelled") {
  const tableGD = {{node:code_node_ymugKpln.data.tableGD}}
  if (tableGD?.length > 0) {
    allData.table_gd = tableGD
  }
}

for (const [index, gdLineItem] of allData.table_gd.entries()) {
  if (!gdLineItem.gd_qty || parseFloat(gdLineItem.gd_qty) === 0) {
    continue;
  }

  const tempQtyData = gdLineItem.temp_qty_data;
  const isEmpty =
    !tempQtyData ||
    tempQtyData === "" ||
    tempQtyData === "[]" ||
    tempQtyData === null;

  if (isEmpty) {
    skippedRows.push({
      index: index,
      material_name: gdLineItem.material_name || "Unknown",
      gd_qty: gdLineItem.gd_qty,
      so_no: gdLineItem.so_no || "",
      reason: "temp_qty_data is empty",
    });
    continue;
  }

  try {
    const parsedTempQty = JSON.parse(tempQtyData);
    const totalAllocated = parsedTempQty.reduce(
      (sum, item) => sum + (parseFloat(item.gd_quantity) || 0),
      0
    );
    const gdQty = parseFloat(gdLineItem.gd_qty) || 0;

    if (Math.abs(totalAllocated - gdQty) > 0.001) {
      skippedRows.push({
        index: index,
        material_name: gdLineItem.material_name || "Unknown",
        gd_qty: gdLineItem.gd_qty,
        allocated_qty: totalAllocated,
        so_no: gdLineItem.so_no || "",
        reason: `temp_qty_data total (${totalAllocated}) != gd_qty (${gdQty})`,
      });
      continue;
    }
  } catch (e) {
    skippedRows.push({
      index: index,
      material_name: gdLineItem.material_name || "Unknown",
      gd_qty: gdLineItem.gd_qty,
      so_no: gdLineItem.so_no || "",
      reason: "temp_qty_data parse error",
    });
    continue;
  }

  gdLineItem.customer_id = allData.customer_name || null;
  gdLineItem.organization_id = allData.organization_id;
  gdLineItem.plant_id = allData.plant_id || null;
  gdLineItem.billing_state_id = allData.billing_address_state || null;
  gdLineItem.billing_country_id = allData.billing_address_country || null;
  gdLineItem.shipping_state_id = allData.shipping_address_state || null;
  gdLineItem.shipping_country_id = allData.shipping_address_country || null;
  gdLineItem.assigned_to = allData.assigned_to || null;
  gdLineItem.area_id = allData.gd_area_id || null;
  gdLineItem.line_index = index + 1;

  if (isForceComplete === "Yes") {
    gdLineItem.picking_status = "Completed";
  } else if (saveAs === "Cancelled") {
